mapper.select:
SELECT i.ISSUE_ID, i.TITLE, i.VERSION_ID, i.PROGRESS_RATE, g.status_name AS issueStatusName, v.VERSION_NAME FROM ISSUE i LEFT JOIN PROJECT_VERSION v ON i.VERSION_ID = v.VERSION_ID LEFT JOIN ISSUE_STATUS g ON i.ISSUE_STATUS_ID = g.ISSUE_STATUS_ID WHERE i.PROJECT_ID = #{projectId} AND i.MILESTONE_ID IS NULL
AND ( i.TITLE LIKE '%' || #{keyword} || '%' OR i.ISSUE_ID LIKE '%' || #{keyword} || '%' OR v.VERSION_NAME LIKE '%' || #{keyword} || '%' )
AND i.VERSION_ID = #{versionId}
